class Solution:
    def smallestNumber(self, num: int) -> int:
        if num == 0:
            return 0
        negative = num < 0
        num = abs(num)
        digits = sorted(str(num))
        if negative:
            digits = digits[::-1]
            return -int(''.join(digits))
        else:
            for i, digit in enumerate(digits):
                if digit != '0':
                    digits.insert(0, digits.pop(i))
                    break
            return int(''.join(digits))
```
